define('taoTests/util/provider/itemClassProvider',['jquery', 'i18n', 'util/url'], function ($, __, urlUtils) {
  'use strict';

  var providers = {
    listTests(data) {
      return new Promise(function (resolve, reject) {
        $.ajax({
          url: urlUtils.route('getItemClasses', 'SaSItems', 'taoItems'),
          data: {
            q: data.q,
            page: data.page
          },
          type: 'GET',
          dataType: 'JSON'
        }).done(function (tests) {
          if (tests) {
            resolve(tests);
          } else {
            reject(new Error(__('Unable to load tests')));
          }
        }).fail(function () {
          reject(new Error(__('Unable to load tests')));
        });
      });
    }
  };
  return providers;
});
