define('taoTests/util/form/itemClassSelectorForm',['jquery', 'i18n', 'ui/filter', 'ui/feedback'], function ($, __, filterFactory, feedback) {
  'use strict';

  return {
    createSelectorInput(_ref) {
      var {
        $filterContainer,
        $inputElement,
        dataProvider,
        inputPlaceholder = __('Select the item destination class'),
        inputLabel = __('Select Item Destination')
      } = _ref;
      return filterFactory($filterContainer, {
        placeholder: inputPlaceholder,
        label: inputLabel,
        width: '64%',
        quietMillis: 1000
      }).on('change', function (selection) {
        $inputElement.val(selection);
      }).on('request', function (params) {
        dataProvider.list(params.data).then(function (data) {
          params.success(data);
        }).catch(function (err) {
          params.error(err);
          feedback().error(err);
        });
      }).render('<%- text %>');
    },
    setupTaoLocalForm($form, providers) {
      var $filterContainer = $('.item-select-container', $form);
      var $inputElement = $('#itemClassDestination', $form);
      this.createSelectorInput({
        $filterContainer,
        $inputElement,
        dataProvider: {
          list: providers.listTests
        }
      });
    }
  };
});
