define('taoTests/controller/tests/editTest',['jquery', 'ui/lock', 'module', 'layout/actions'], function ($, lock, module, actions) {
  'use strict';

  return {
    start() {
      var config = module.config();
      var maxButtons = 10;
      var getPreviewId = idx => "test-preview".concat(idx ? "-".concat(idx) : '');
      var previewActions = [];
      for (var i = 0; i < maxButtons; i++) {
        var action = actions.getBy(getPreviewId(i));
        if (!action) {
          break;
        }
        previewActions.push(action);
      }
      previewActions.forEach(previewAction => {
        previewAction.state.disabled = !config.isPreviewEnabled;
      });
      actions.updateState();
      $('#lock-box').each(function () {
        lock($(this)).register();
      });
    }
  };
});
